# VPN Connection Validator and Zero Trust Checker
import ssl
import socket
import hashlib
from datetime import datetime, timedelta
from typing import Dict, List

class ZeroTrustVerifier:
    def __init__(self):
        self.trusted_devices = {}
        self.access_policies = {}
        self.session_tokens = {}

    def register_device(self, device_id, public_key, metadata):
        """Register a device for zero trust verification."""
        self.trusted_devices[device_id] = {
            'public_key': public_key,
            'registered': datetime.now(),
            'last_seen': datetime.now(),
            'trust_score': 0.5,
            'metadata': metadata
        }

    def verify_device(self, device_id, presented_token):
        """Verify device identity and trust score."""
        if device_id not in self.trusted_devices:
            return {'allowed': False, 'reason': 'Unknown device'}

        device = self.trusted_devices[device_id]
        age = datetime.now() - device['last_seen']

        # Reduce trust if device hasn't checked in recently
        if age > timedelta(days=30):
            device['trust_score'] *= 0.5

        # Check minimum trust threshold
        if device['trust_score'] < 0.3:
            return {'allowed': False, 'reason': 'Trust score too low'}

        device['last_seen'] = datetime.now()
        return {'allowed': True, 'trust_score': device['trust_score']}

    def check_vpn_tunnel(self, host, port=443):
        """Verify VPN tunnel integrity via TLS certificate."""
        context = ssl.create_default_context()
        try:
            with socket.create_connection((host, port), timeout=10) as sock:
                with context.wrap_socket(sock, server_hostname=host) as ssock:
                    cert = ssock.getpeercert()
                    cipher = ssock.cipher()
                    return {
                        'status': 'secure',
                        'protocol': ssock.version(),
                        'cipher': cipher[0],
                        'cert_issuer': dict(x[0] for x in cert['issuer']),
                        'expires': cert['notAfter']
                    }
        except Exception as e:
            return {'status': 'failed', 'error': str(e)}

    def enforce_least_privilege(self, user_role, requested_resource):
        """Enforce zero trust access policy."""
        policies = {
            'admin': ['*'],
            'developer': ['code_repo', 'staging_db', 'logs'],
            'analyst': ['dashboard', 'reports'],
            'viewer': ['dashboard']
        }
        allowed = policies.get(user_role, [])
        if '*' in allowed or requested_resource in allowed:
            return {'granted': True}
        return {'granted': False, 'reason': f'{user_role} cannot access {requested_resource}'}
